void GameServer::SendGameStateToClients() {
    // Construct the game state packet dynamically
    size_t packetHeaderSize = sizeof(S2C_GameStatePacketHeader);
    size_t playerNetStateSize = sizeof(S2C_PlayerNetState);

    std::vector<S2C_PlayerNetState> playerStatesToSend;
    for (const auto& pair : activeClients) {
        if (pair.second.playerState.isConnected) {
            S2C_PlayerNetState netState;
            netState.playerId = pair.second.playerState.playerId;
            netState.posX = pair.second.playerState.position.x;
            netState.posY = pair.second.playerState.position.y;
            netState.posZ = pair.second.playerState.position.z;
            netState.pitch = pair.second.playerState.orientation.pitch;
            netState.yaw = pair.second.playerState.orientation.yaw;
            netState.actions = pair.second.playerState.currentActions; // Actions that happened this tick
            playerStatesToSend.push_back(netState);
        }
    }

    // Calculate the total size required for the packet
    size_t totalPacketSize = packetHeaderSize + (playerStatesToSend.size() * playerNetStateSize);
    
    // Warn if the packet size exceeds typical MTU (Maximum Transmission Unit) to avoid fragmentation.
    // For simplicity, we cap it, but a real game might send multiple packets or compress data.
    if (totalPacketSize > MAX_PACKET_SIZE) {
        std::cerr << "Warning: Game state packet (" << totalPacketSize << " bytes) exceeds MAX_PACKET_SIZE (" << MAX_PACKET_SIZE << " bytes). Truncating.\n";
        totalPacketSize = MAX_PACKET_SIZE; 
    }

    std::vector<char> sendBuffer(totalPacketSize);

    S2C_GameStatePacketHeader* header = reinterpret_cast<S2C_GameStatePacketHeader*>(sendBuffer.data());
    header->type = PacketType::S2C_GAME_STATE;
    header->serverTick = serverTickCount;
    // We update numPlayers here to reflect potentially truncated data if totalPacketSize was capped
    header->numPlayers = (totalPacketSize - packetHeaderSize) / playerNetStateSize;

    char* currentPtr = sendBuffer.data() + packetHeaderSize;
    for (size_t i = 0; i < playerStatesToSend.size(); ++i) {
        // Only copy player states that fit within the `totalPacketSize` limit
        if (currentPtr + playerNetStateSize <= sendBuffer.data() + totalPacketSize) {
            memcpy(currentPtr, &playerStatesToSend[i], playerNetStateSize);
            currentPtr += playerNetStateSize;
        } else {
            // Adjust numPlayers in header if we had to truncate
            header->numPlayers = i;
            break; 
        }
    }

    // Send the constructed packet to all active clients
    for (const auto& pair : activeClients) {
        if (pair.second.playerState.isConnected) {
            const sockaddr_in& clientAddress = pair.second.address;
            sendto(serverSocket, sendBuffer.data(), totalPacketSize, 0,
                   (sockaddr*)&clientAddress, sizeof(clientAddress));
        }
    }
}

void GameServer::RemoveInactiveClients() {
    auto now = std::chrono::steady_clock::now();
    std::vector<uint32_t> clientsToDisconnect;

    for (const auto& pair : activeClients) {
        if (now - pair.second.lastActivity > CLIENT_TIMEOUT_SEC) {
            clientsToDisconnect.push_back(pair.first);
        }
    }

    for (uint32_t playerId : clientsToDisconnect) {
        auto it = activeClients.find(playerId);
        if (it != activeClients.end()) {
            std::cout << "Player " << playerId << " from "
                      << inet_ntoa(it->second.address.sin_addr) << ":" << ntohs(it->second.address.sin_port)
                      << " timed out. Disconnecting.\n";
            addressToPlayerId.erase(it->second.address); // Remove mapping
            activeClients.erase(it); // Remove client
        }
    }
}

